mapper.delete:
DELETE FROM FWK_MESSAGE
WHERE ORG_ID = #{orgId}
  AND MESSAGE_ID = #{messageId}

mapper.select:
SELECT COUNT(*)
FROM FWK_MESSAGE
WHERE ORG_ID = #{orgId}
  AND MESSAGE_ID = #{messageId}

