SELECT NVL(MAX(VERSION), 0)
FROM FWK_MESSAGE_HISTORY
WHERE ORG_ID = #{orgId} AND MESSAGE_ID = #{messageId}

mapper.update:
UPDATE FWK_MESSAGE
SET CUR_VERSION = #{version},
    LAST_UPDATE_DTIME = #{lastUpdateDtime},
    LAST_UPDATE_USER_ID = #{lastUpdateUserId}
WHERE ORG_ID = #{orgId} AND MESSAGE_ID = #{messageId}

mapper.select:
SELECT fp.FIELD_DOMAIN_ID AS fieldDomainId, CASE WHEN fp.FIELD_DOMAIN_ID IS NOT NULL THEN 'Y' END AS domainRegistryYn, t.FIELD_ID AS messageFieldId, CASE WHEN fp.MESSAGE_FIELD_ID IS NOT NULL THEN 'Y' END AS fieldRegistryYn FROM (
SELECT #{id} AS FIELD_ID FROM DUAL
) t LEFT JOIN FWK_FIELD_POOL fp ON fp.MESSAGE_FIELD_ID = t.FIELD_ID
